<header class="app-page-head"><div><p class="eyebrow"><?=e($entry['brand']?:'Deine Bewertung')?></p><h1><?=e($entry['product_name'])?></h1><p>Zuletzt probiert am <?=e(substr((string)$entry['last_tried_at'],0,10))?></p></div><div class="big-rating"><strong><?=e($entry['overall_rating'])?></strong><span>/10</span></div></header>
<section class="entry-summary"><div><h2>Dein Urteil</h2><p class="entry-note"><?=e($entry['note']?:'Noch keine Notiz.')?></p><div class="product-flags"><?php foreach($tags as $tag):?><span><?=e($tag['label'])?></span><?php endforeach;?></div><a class="button button-secondary" href="<?=str_starts_with($entry['product_key'],'off:')?u('/app/product/'.urlencode((string)$entry['barcode'])):u('/app/custom/'.(int)$entry['custom_product_id'])?>">Bewertung bearbeiten</a></div><div class="score-ticket"><span>Geschmack</span><b><?=e($entry['taste_rating']??'–')?></b><span>Textur</span><b><?=e($entry['texture_rating']??'–')?></b><span>Preis-Leistung</span><b><?=e($entry['value_rating']??'–')?></b><span>Wieder kaufen</span><b><?=e(['yes'=>'Ja','maybe'=>'Vielleicht','no'=>'Nein'][$entry['buy_again']]??'–')?></b></div></section>
<?php if($prices):?><section class="section-head"><div><p class="eyebrow">Preisverlauf</p><h2>Deine Käufe</h2></div></section><div class="price-list"><?php foreach($prices as $price):?><div><strong><?=fmt_price($price['price'],$price['currency'])?></strong><span><?=e($price['store_name_snapshot']?:'Ohne Kaufort')?> · <?=e($price['purchased_at'])?></span></div><?php endforeach;?></div><?php endif;?>
<?php if($photos):?><section class="photo-grid"><?php foreach($photos as $photo):?><img src="<?=u('/media/review/'.(int)$photo['id'])?>" alt="<?=e($photo['alt_text']?:$entry['product_name'])?>" loading="lazy"><?php endforeach;?></section><?php endif;?>
<section class="collection-add"><h2>Zu einer Sammlung</h2><?php if($collections):?><form method="post" action="<?=u('/app/collections/add')?>" class="inline-form"><?=$csrf?><input type="hidden" name="product_key" value="<?=e($entry['product_key'])?>"><label class="sr-only" for="collection_id">Sammlung</label><select id="collection_id" name="collection_id" required><?php foreach($collections as $collection):?><option value="<?=e($collection['id'])?>"><?=e($collection['name'])?></option><?php endforeach;?></select><button class="button" type="submit">Hinzufügen</button></form><?php else:?><a href="<?=u('/app/collections')?>">Erste Sammlung erstellen →</a><?php endif;?></section>
<section class="collection-add"><p class="eyebrow">Optional teilen</p><h2>Bereinigte Bildkarte und Link</h2><p>Notiz, Preise, Fotos, E-Mail und interne Kennungen bleiben privat.</p><form method="post" action="<?=u('/app/shares/create')?>"><?=$csrf?><input type="hidden" name="share_type" value="review"><input type="hidden" name="resource_id" value="<?=e($entry['id'])?>"><button class="button button-secondary" type="submit">Widerrufbaren Link erzeugen</button></form><a href="<?=u('/app/shares')?>">Aktive Freigaben verwalten →</a></section>
